INSERT INTO catalog_recommendationrule (id, created_at, updated_at, max_score_threshold, title, description, priority, effort, measure_type, owner_role, target_phase, sort_order, question_id) VALUES (1, '2026-04-19 08:26:18.235490', '2026-04-19 08:26:18.235498', 2, 'ISMS-Scope formalisieren und genehmigen.', 'Diese Massnahme wird empfohlen, weil die Frage "Ist der Geltungsbereich des ISMS definiert und dokumentiert?" derzeit nicht ausreichend beantwortet wurde.', 'HIGH', 'SMALL', 'DOCUMENTARY', 'ISMS Manager', 'Phase 1 – Governance', 10, 6) ON CONFLICT (id) DO NOTHING;
INSERT INTO catalog_recommendationrule (id, created_at, updated_at, max_score_threshold, title, description, priority, effort, measure_type, owner_role, target_phase, sort_order, question_id) VALUES (2, '2026-04-19 08:26:18.331776', '2026-04-19 08:26:18.331785', 2, 'RACI und Verantwortlichkeiten fuer CISO, Process Owner und Risk Owner festlegen.', 'Diese Massnahme wird empfohlen, weil die Frage "Sind Rollen und Verantwortlichkeiten fuer Informationssicherheit dokumentiert?" derzeit nicht ausreichend beantwortet wurde.', 'HIGH', 'SMALL', 'ORGANIZATIONAL', 'ISMS Manager', 'Phase 1 – Governance', 10, 7) ON CONFLICT (id) DO NOTHING;
INSERT INTO catalog_recommendationrule (id, created_at, updated_at, max_score_threshold, title, description, priority, effort, measure_type, owner_role, target_phase, sort_order, question_id) VALUES (3, '2026-04-19 08:26:18.435037', '2026-04-19 08:26:18.435045', 2, 'IS-Policy erstellen, genehmigen und kommunizieren.', 'Diese Massnahme wird empfohlen, weil die Frage "Gibt es eine freigegebene Informationssicherheits-Policy?" derzeit nicht ausreichend beantwortet wurde.', 'CRITICAL', 'SMALL', 'DOCUMENTARY', 'ISMS Manager', 'Phase 1 – Governance', 10, 8) ON CONFLICT (id) DO NOTHING;
INSERT INTO catalog_recommendationrule (id, created_at, updated_at, max_score_threshold, title, description, priority, effort, measure_type, owner_role, target_phase, sort_order, question_id) VALUES (4, '2026-04-19 08:26:18.539189', '2026-04-19 08:26:18.539206', 2, 'Management-Review-Prozess mit Agenda und Teilnehmern etablieren.', 'Diese Massnahme wird empfohlen, weil die Frage "Wird eine regelmaessige Management-Review durchgefuehrt?" derzeit nicht ausreichend beantwortet wurde.', 'HIGH', 'SMALL', 'ORGANIZATIONAL', 'ISMS Manager', 'Phase 6 – Audit Readiness', 10, 9) ON CONFLICT (id) DO NOTHING;
